1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	};
8	
9	interface Item {
10	  type: string;
11	}
12	
13	interface QuoteStep {
14	  op: "quote";
15	  items: Item[];
16	}
17	
18	interface Scenario {
19	  customer: { yearsWithMHPCO: number };
20	  steps: QuoteStep[];
21	}
22	
23	export function runScenario(input: unknown): unknown {
24	  const scenario = input as Scenario;
25	  const results = scenario.steps.map((step) => {
26	    const basePremium = step.items.reduce(
27	      (sum, item) => sum + (BASE_PREMIUM[item.type] ?? 0),
28	      0,
29	    );
30	    const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
31	    const premium = basePremium + firstInsurance + PROCESSING_FEE;
32	    return { premium };
33	  });
34	  return { results };
35	}
